finetune_examples.input:
// Noncompliant: deletes and then writes new file
std::filesystem::remove(path);
std::ofstream out(path);
out << data;

finetune_examples.output:
// Compliant: write temp and rename atomically
auto temp = path.string() + ".tmp";
{
  std::ofstream out(temp, std::ios::binary);
  out << data;
  out.flush();
  out.close();
}
std::filesystem::rename(temp, path);

finetune_examples.input:
// Noncompliant: Files.delete then Files.write
Files.deleteIfExists(path);
Files.write(path, data);

finetune_examples.output:
// Compliant: write to temp and move atomically
Path tmp = Files.createTempFile(path.getParent(), "temp", null);
Files.write(tmp, data);
Files.move(tmp, path, StandardCopyOption.ATOMIC_MOVE, StandardCopyOption.REPLACE_EXISTING);

